let first = $input.first()?.json || {};
let generated = null;
try { generated = $('Parse Script Package').first().json; } catch (e) { generated = null; }
const payload = generated || first.body || first;
const sources = payload.raizSources || payload.googleSources || {};

if (payload.shouldContinue === false) {
  return [{ json: { machine: 'RAIZ Shorts Factory', stage: 'no_ready_rows', status: 'idle', message: payload.message || 'No ready video rows found.', googleSources: sources } }];
}

const topic = payload.title_working || payload.topic || payload.idea || payload.idea_text || 'الانطفاء اللامع';
const angle = payload.hook || payload.hook_angle || payload.angle || 'حالة إنسان حديث ينجز من الخارج وينطفئ بهدوء من الداخل';
const tone = payload.tone || payload.creative_direction || 'عربي معاصر، بصري، مكثف، غير وعظي';
const duration = Number(payload.duration_target_sec || payload.duration || 35);
const now = new Date().toISOString();
const generatedId = `raiz-${now.replace(/[-:.TZ]/g, '').slice(0, 14)}`;
const videoId = payload.video_id || payload.idea_id || generatedId;

const title = payload.youtube_title || `${topic} | مشاعر العصر الجديد #shorts`;
const voiceover = payload.voiceover_text || `${angle}\n${payload.idea_text || ''}\nسمّه بدل ما يبتلعك.`;
const captions = Array.isArray(payload.captions) && payload.captions.length ? payload.captions : [angle, payload.idea_text || '', 'سمّه بدل ما يبتلعك.'].filter(Boolean);
const scriptText = payload.script_final_arabic || voiceover;
const visualPlan = Array.isArray(payload.visual_plan) ? payload.visual_plan : [];

return [{
  json: {
    machine: 'RAIZ Shorts Factory',
    stage: 'package_ready',
    createdAt: now,
    source: payload.source || 'google_sheet',
    video_id: videoId,
    idea_id: payload.idea_id || null,
    googleSources: sources,
    masterContextLoaded: Boolean(payload.masterContextLoaded),
    topic,
    angle,
    tone,
    format: {
      platform: payload.platform_primary || 'YouTube Shorts',
      aspectRatio: payload.format || '9:16',
      resolution: '1080x1920',
      targetDurationSeconds: duration,
      language: payload.language || 'ar',
      rtl: true
    },
    script: {
      hook: angle,
      body: scriptText,
      cta: 'سمّه بدل ما يبتلعك.',
      voiceover,
      captions
    },
    visualDirection: {
      style: tone,
      scenes: visualPlan.length ? visualPlan : [
        'Opening black frame with one sharp Arabic sentence',
        'Abstract data fracture around document edge',
        'Central text card with controlled red underline',
        'Final term lockup and CTA'
      ]
    },
    renderPayload: {
      video_id: videoId,
      template: payload.template_id || payload.template || payload.render_template || 'new_era_dark_editorial',
      output: 'mp4',
      format: payload.format || '9:16',
      width: 1080,
      height: 1920,
      size: { width: 1080, height: 1920 },
      fps: 30,
      duration,
      language: payload.language || 'ar',
      rtl: true,
      topic,
      angle,
      voiceover,
      captions,
      scenes: visualPlan,
      text: { hook: angle, body: scriptText, cta: 'سمّه بدل ما يبتلعك.', direction: 'rtl', language: payload.language || 'ar' },
      audio: { voiceoverText: voiceover, voice: payload.voice || 'arabic-calm-confident' },
      sources: {
        spreadsheetId: sources.googleSheet?.spreadsheetId,
        documentId: sources.googleDoc?.documentId,
        masterContextLoaded: Boolean(payload.masterContextLoaded)
      },
      brand: { footer: '© 2025 Nabil88 | nabil88.art' }
    },
    youtube: {
      title,
      description: payload.youtube_description || `${scriptText}\n\n#shorts #مشاعر_العصر_الجديد #nabil88`,
      tags: 'shorts,arabic,مشاعر العصر الجديد,nabil88,RAIZ',
      categoryId: '22',
      privacyStatus: payload.privacyStatus || 'private',
      madeForKids: false
    }
  }
}];

const sources = {
  googleSheet: {
    name: 'RAIZ Video Factory Control Sheet v1',
    spreadsheetId: '1feNLjbK6jfYVAz6wofPIawwcth8BTLK-cvxu30zZAvE',
    url: 'https://docs.google.com/spreadsheets/d/1feNLjbK6jfYVAz6wofPIawwcth8BTLK-cvxu30zZAvE/edit?usp=drivesdk',
    primarySheet: 'VIDEOS_MASTER',
    docsLibrarySheet: 'DOCS_LIBRARY',
    readyRule: 'main_status=APPROVED AND n8n_lock=FALSE'
  },
  googleDoc: {
    name: 'RAIZ Video Factory Master Context',
    documentId: '1y5YBKIYTQo15sI_ts-Wu8x59aJLoE7qxNV0vBp0Vwz4',
    url: 'https://docs.google.com/document/d/1y5YBKIYTQo15sI_ts-Wu8x59aJLoE7qxNV0vBp0Vwz4/edit?usp=drivesdk',
    docType: 'PROJECT_CONTEXT',
    usage: 'Master context used before script, captions, visual plan, and render payload generation.'
  },
  note: 'Google OAuth runtime connection are still required before n8n can read Sheets/Docs directly.'
};

return $input.all().map((item) => ({
  json: {
    ...item.json,
    raizSources: sources
  }
}));

const rows = $input.all().map((item) => item.json);

const isUnlocked = (value) => {
  if (value === false || value === 0 || value === null || value === undefined || value === '') return true;
  if (String(value).trim().toUpperCase() === 'FALSE') return true;
  return false;
};

const ready = rows
  .filter((row) => String(row.main_status || '').trim().toUpperCase() === 'APPROVED')
  .filter((row) => isUnlocked(row.n8n_lock))
  .sort((a, b) => Number(a.priority || 999) - Number(b.priority || 999));

if (!ready.length) {
  return [{
    json: {
      stage: 'no_ready_rows',
      message: 'No VIDEOS_MASTER row matched main_status=APPROVED and n8n_lock=FALSE.',
      shouldContinue: false
    }
  }];
}

const selected = ready[0];

return [{
  json: {
    ...selected,
    shouldContinue: true,
    source: 'google_sheet',
    raizSources: {
      googleSheet: {
        name: 'RAIZ Video Factory Control Sheet v1',
        spreadsheetId: '1feNLjbK6jfYVAz6wofPIawwcth8BTLK-cvxu30zZAvE',
        primarySheet: 'VIDEOS_MASTER',
        readyRule: 'main_status=APPROVED AND n8n_lock=FALSE'
      },
      googleDoc: {
        name: 'RAIZ Video Factory Master Context',
        documentId: '1y5YBKIYTQo15sI_ts-Wu8x59aJLoE7qxNV0vBp0Vwz4',
        docType: 'PROJECT_CONTEXT'
      }
    }
  }
}];

const doc = $input.first()?.json || {};
let video = {};
try {
  video = $('Pick Next Approved Video').first().json || {};
} catch (error) {
  video = {};
}

return [{
  json: {
    ...video,
    masterContext: doc.content || '',
    masterContextDocumentId: doc.documentId || '1y5YBKIYTQo15sI_ts-Wu8x59aJLoE7qxNV0vBp0Vwz4',
    masterContextLoaded: Boolean(doc.content)
  }
}];

const now = new Date().toISOString();
return $input.all().map((item) => ({
  json: {
    video_id: item.json.video_id,
    n8n_lock: true,
    locked_by: $execution.id,
    locked_at: now,
    current_stage: 'SCRIPT',
    updated_at: now
  }
}));

const video = $input.first().json;
const context = video.masterContext || '';
const prompt = `اكتب حزمة إنتاج فيديو YouTube Shorts عربية بنظام RAIZ Video Factory.

المطلوب إخراج JSON صالح فقط، بدون Markdown، بهذا الشكل:
{
  "hook": "...",
  "script_final_arabic": "...",
  "voiceover_text": "...",
  "captions": ["..."],
  "visual_plan": [{"scene_id":"S01","time":"0-5s","visual":"...","caption":"...","audio":"..."}],
  "youtube_title": "...",
  "youtube_description": "...",
  "render_notes": "...",
  "quality_notes": "..."
}

قواعد ثابتة:
- اللغة عربية.
- المدة المستهدفة: ${video.duration_target_sec || 45} ثانية.
- لا تستخدم وعظ مباشر.
- النص قصير، بصري، قوي، قابل للتعليق الصوتي.
- الكابتشن جمل قصيرة جدًا تظهر على الشاشة.
- الهوية: ${video.creative_direction || 'أسود وأبيض، دفء إنساني، نص عربي واضح'}.
- أضف footer في الملاحظات: © 2025 Nabil88 | nabil88.art

بيانات الفيديو:
video_id: ${video.video_id}
title_working: ${video.title_working}
idea_text: ${video.idea_text}
hook_angle: ${video.hook_angle}
audience: ${video.audience}
category: ${video.category}
series_name: ${video.series_name}

قالب/مرجع Google Doc:
${context.slice(0, 5000)}
`;
return [{ json: { ...video, aiPrompt: prompt } }];

const ai = $input.first().json;
const video = $('Attach Master Context').first().json;

function findJsonString(value) {
  if (typeof value === 'string') return value;
  if (Array.isArray(value)) {
    for (const v of value) {
      const found = findJsonString(v);
      if (found) return found;
    }
  }
  if (value && typeof value === 'object') {
    for (const k of ['output_text','text','content','message','response','data']) {
      if (value[k]) {
        const found = findJsonString(value[k]);
        if (found) return found;
      }
    }
    for (const v of Object.values(value)) {
      const found = findJsonString(v);
      if (found) return found;
    }
  }
  return '';
}

let raw = findJsonString(ai) || JSON.stringify(ai);
raw = raw.replace(/```json|```/g, '').trim();
let parsed;
try {
  parsed = JSON.parse(raw);
} catch (error) {
  parsed = {
    hook: video.hook_angle || 'إنت مش تعبان… إنت شغال وجزء منك مطفّي',
    script_final_arabic: `${video.hook_angle || ''}\n${video.idea_text || ''}\nسمّه بدل ما يبتلعك.`,
    voiceover_text: `${video.hook_angle || ''}\n${video.idea_text || ''}\nسمّه بدل ما يبتلعك.`,
    captions: [video.hook_angle || 'إنت مش تعبان…', video.idea_text || 'جزء منك مطفّي بهدوء.', 'سمّه بدل ما يبتلعك.'],
    visual_plan: [
      { scene_id: 'S01', time: '0-5s', visual: video.creative_direction || 'black and white Arabic editorial frame', caption: video.hook_angle || '', audio: 'quiet pulse' }
    ],
    youtube_title: `${video.title_working || 'RAIZ Short'} | #shorts`,
    youtube_description: `${video.idea_text || ''}\n\n#shorts #nabil88`,
    render_notes: 'Fallback package because AI JSON parse failed.',
    quality_notes: error.message
  };
}

const now = new Date().toISOString();
const captions = Array.isArray(parsed.captions) ? parsed.captions : String(parsed.captions || '').split('\n').filter(Boolean);
const visualPlan = Array.isArray(parsed.visual_plan) ? parsed.visual_plan : [];
const voiceover = parsed.voiceover_text || parsed.script_final_arabic || captions.join('\n');

return [{
  json: {
    ...video,
    generatedAt: now,
    aiRaw: ai,
    hook: parsed.hook || video.hook_angle,
    script_final_arabic: parsed.script_final_arabic || voiceover,
    voiceover_text: voiceover,
    captions,
    visual_plan: visualPlan,
    youtube_title: parsed.youtube_title || `${video.title_working || 'RAIZ Short'} | #shorts`,
    youtube_description: parsed.youtube_description || `${video.idea_text || ''}\n\n#shorts #nabil88`,
    render_notes: parsed.render_notes || '',
    quality_notes: parsed.quality_notes || '',
    ai_parse_status: 'OK'
  }
}];

const p = $input.first().json;
const now = new Date().toISOString();
const videoId = p.video_id;
const version = 1;
const base = {
  video_id: videoId,
  version,
  status: 'READY',
  duration_sec: Number(p.duration_target_sec || 45),
  voice_model: 'arabic-calm-confident',
  caption_style: 'Arabic Bold Bottom',
  render_template: p.template_id || p.render_template || 'new_era_dark_editorial',
  created_by: 'n8n/OpenAI',
  created_at: now,
  updated_at: now
};
const renderPayload = {
  video_id: videoId,
  template: p.template_id || 'new_era_dark_editorial',
  format: p.format || '9:16',
  width: 1080,
  height: 1920,
  fps: 30,
  duration: Number(p.duration_target_sec || 45),
  language: p.language || 'ar',
  rtl: true,
  topic: p.title_working,
  angle: p.hook || p.hook_angle,
  voiceover: p.voiceover_text,
  captions: p.captions,
  scenes: p.visual_plan,
  brand: { footer: '© 2025 Nabil88 | nabil88.art' }
};
return [
  { json: { asset_id: `AST-${videoId}-SCRIPT-${Date.now()}`, ...base, asset_type: 'SCRIPT', content_text: p.script_final_arabic, notes: 'Generated final Arabic script' } },
  { json: { asset_id: `AST-${videoId}-VOICE-${Date.now()}`, ...base, asset_type: 'VOICEOVER_TEXT', content_text: p.voiceover_text, notes: 'Generated voiceover text' } },
  { json: { asset_id: `AST-${videoId}-CAPTIONS-${Date.now()}`, ...base, asset_type: 'CAPTIONS', content_text: p.captions.join('\n'), json_payload: JSON.stringify(p.captions), notes: 'Generated on-screen captions' } },
  { json: { asset_id: `AST-${videoId}-VISUAL-${Date.now()}`, ...base, asset_type: 'VISUAL_PLAN', content_text: p.render_notes || '', json_payload: JSON.stringify(p.visual_plan), notes: 'Generated scene/visual plan' } },
  { json: { asset_id: `AST-${videoId}-RENDER-${Date.now()}`, ...base, asset_type: 'RENDER_PAYLOAD', content_text: null, json_payload: JSON.stringify(renderPayload), notes: 'Draft render payload for RAIZ Video' } }
];

const p = $('Parse Script Package').first().json;
const now = new Date().toISOString();
return [{ json: { video_id: p.video_id, main_status: 'SCRIPT_READY', current_stage: 'RENDER_PAYLOAD', n8n_lock: false, locked_by: '', locked_at: '', quality_status: 'PENDING', updated_at: now, notes: 'Script, captions, visual plan, and render payload generated by n8n.' } }];

const p = $('Parse Script Package').first().json;
const now = new Date().toISOString();
return [{ json: { run_id: `RUN-${Date.now()}`, video_id: p.video_id, workflow_name: 'daily_short_factory_v1', execution_id: $execution.id, stage: 'SCRIPT', event_type: 'SUCCESS', status_before: 'APPROVED', status_after: 'SCRIPT_READY', started_at: p.generatedAt || now, finished_at: now, duration_sec: 0, error_id: '', error_message: '', retry_count_after: Number(p.retry_count || 0), next_action: 'Render payload ready. Configure RAIZ render API next.', raw_response_json: JSON.stringify({ hook: p.hook, captions: p.captions, visual_plan_count: p.visual_plan?.length || 0 }), notes: 'Script assets generated and saved.' } }];

const rows = $input.all().map(i => i.json);
const cap = 9;
const activeStatuses = new Set(['SCRIPT_READY', 'RENDERED']);
const pipelineCount = rows.filter(r => activeStatuses.has(String(r.main_status || '').trim().toUpperCase())).length;

if (pipelineCount >= cap) {
  return [];
}

let base = {};
try { base = $('RAIZ Google Sources Config').first().json || {}; } catch (e) { base = {}; }

return [{ json: { ...base, pipeline_count: pipelineCount, total_inventory_cap: cap, capacity_available: cap - pipelineCount } }];
